-- 지난 설교 암송 도우미 백필 (scripts/4b-versehelp.mjs 자동 생성)
-- Supabase SQL Editor 에 붙여넣어 실행하세요. easy_explain·memory_tip 두 컬럼만 바꿉니다.
alter table public.sermons add column if not exists easy_explain text;
alter table public.sermons add column if not exists memory_tip   text;

update public.sermons set
  easy_explain = $H$밤새 고기를 못 잡고 지쳐 있던 베드로에게 예수님이 하신 말씀이에요. 여기서 '무서워하지 말라'는, 못난 나 자신 때문에 겁내지 말라는 다독임이에요. '사람을 취하리라'는, 이제부터 사람을 살리고 하나님께 데려오는 일을 맡기신다는 뜻이에요. 자격 없는 나를 그냥 믿어 주시고 부르시는 은혜가 담긴 말씀이랍니다.$H$,
  memory_tip   = $H$'무서워하지 말라 / 이제 후로는 / 네가 사람을 취하리라' 세 덩어리로 끊어 외워 보세요. 앞은 다독임, 뒤는 부르심이라 대비를 이룹니다. 지친 베드로에게 예수님이 손 내미시는 장면을 그리며 소리 내면 잘 붙습니다.$H$
where id = '1UcdPyDNJFg';   -- 눅 5:10 은혜라서 감사
update public.sermons set
  easy_explain = $H$바울이 전하는 이 가르침이 어디서 왔는지 알려주는 구절이에요. 바른 교훈은 사람이 지어낸 멋진 지식이 아니라, '복되신 하나님'의 '영광의 복음'에서 나온 것이라는 말씀이지요. 여기서 '복음'은 예수님을 통해 우리를 구원하시는 기쁜 소식이에요. 반짝이는 유리 보석 같은 가짜에 속지 말고, 하나님께서 주신 진짜 복음을 따르라는 뜻이랍니다.$H$,
  memory_tip   = $H$세 덩어리로 끊어 외워 보세요. '이 교훈은 / 내게 맡기신 바 / 복되신 하나님의 영광의 복음을 따름이니라.' 특히 '복되신 하나님의 영광의 복음'은 '복-영광-복음'으로 좋은 말이 이어지니, 이 흐름을 그려 보며 반복하면 잘 외워져요.$H$
where id = 'KEDbbyZuM9g';   -- 딤전 1:11 유리 보석에 속지 마십시오
update public.sermons set
  easy_explain = $H$예수님은 끝까지 믿음을 지키며 이기는 사람에게 생명나무 열매를 주겠다고 약속하세요. 여기서 '이기는 그'는 힘이 센 사람이 아니라, 삶이 영적 전쟁터 같아도 예수님만 바라보며 끝까지 견디는 사람이에요. '생명나무의 열매'는 하나님 나라에서 누리는 영원한 생명과 기쁨을 뜻해요. 처음 사랑을 회복하고 주님만 바라보면 이 놀라운 상을 받게 됩니다.$H$,
  memory_tip   = $H$이 구절은 '누가→무엇을→어떻게'로 끊으면 쉬워요. '이기는 그에게는 / 내가 하나님의 낙원에 있는 / 생명나무의 열매를 주어 / 먹게 하리라' 네 덩어리로 나눠 반복하세요. 낙원의 나무에서 열매를 따 먹는 장면을 그리면 잘 외워집니다.$H$
where id = 'qY_mGiV6YrE';   -- 계 2:7 교회에 왔더니 예수만 보여요
update public.sermons set
  easy_explain = $H$바울 일행은 꿈에서 '마게도냐로 건너와서 도우라'는 음성을 들었어요. 이 구절은 그 음성을 사람 말이 아니라 하나님이 우리를 부르신 것이라고 확실히 믿었다는 뜻이에요. 여기서 '인정함'은 '아, 이건 하나님의 부르심이구나 하고 확신했다'는 말이에요. 그래서 바울은 망설이지 않고 바로 바다를 건너 순종했답니다.$H$,
  memory_tip   = $H$'하나님이 → 저 사람들에게 복음을 전하라고 → 우리를 부르신 줄로 → 인정함이러라' 이렇게 네 덩어리로 끊어 외워 보세요. '부르신 줄로 인정함'이 핵심이니 이 부분을 크게 소리 내어 반복하면 잘 외워집니다.$H$
where id = '5LJruOQx-4k';   -- 행 16:10 건너와서 도우라
update public.sermons set
  easy_explain = $H$천사가 마리아를 찾아와 건넨 인사예요. '은혜를 받은 자여'는 '하나님께 특별한 사랑을 받은 사람'이라는 뜻이에요. 여기서 '평안'은 걱정 없이 마음이 든든한 상태를 말해요. 천사는 마리아에게 '하나님이 너와 함께 계시니 안심하라'고 말해 준 거예요. 나도 부족하지만 하나님의 은혜를 받은 사람이라는 걸 기억하며 마음의 평안을 누리라는 말씀이에요.$H$,
  memory_tip   = $H$세 덩어리로 끊어 외워 보세요. ①'은혜를 받은 자여' ②'평안할지어다' ③'주께서 너와 함께하시도다'. 천사가 마리아 앞에서 이 세 마디를 차례로 건네는 장면을 그려 보면 순서가 잘 떠오릅니다. 마지막은 '함께하시도다'로 끝난다는 점을 기억하세요.$H$
where id = 'yKGONbd_7Rg';   -- 눅 1:28 은혜를 받은 자여
update public.sermons set
  easy_explain = $H$다윗은 자기를 죽이려던 사울을 죽일 기회가 있었지만 그 생명을 소중히 여겨 살려 주었어요. 이 구절은 '제가 왕의 목숨을 귀하게 여긴 것처럼, 하나님도 제 목숨을 귀하게 여겨 어려움에서 건져 주세요'라는 다윗의 기도예요. 여기서 '중히 여긴다'는 말은 '아주 소중하게 대한다'는 뜻이에요. 남의 생명을 아끼면 하나님이 내 생명도 아껴 주신다는 믿음이 담겨 있답니다.$H$,
  memory_tip   = $H$구절이 '내가 …한 것 같이 / 여호와께서 …하셔서 / 나를 구하여 내시기를'로 이어지는 대구 구조예요. '왕의 생명→내 생명'이 짝을 이루니 이 두 '생명'을 붙잡아 외워 보세요. 다윗이 사울을 살려 주는 장면을 그리며 기도하듯 읽으면 잘 외워져요.$H$
where id = 'JfGTRQE7uNY';   -- 삼상 26:24 으른입니까, 어른입니까?
update public.sermons set
  easy_explain = $H$무덤을 찾아온 여인들에게 천사가 전한 말이에요. 여기서 '나사렛 예수'는 십자가에서 돌아가신 그 예수님을 가리켜요. 그런데 놀랍게도 '그가 살아나셨고 여기 계시지 아니하니라', 즉 무덤이 텅 비었다는 소식이에요. 죽음으로 끝난 줄 알았던 자리가 도리어 부활의 소망이 시작되는 자리가 되었답니다. 손에 든 향품이 쓸모없어진 빈 무덤 앞에서, 다시 사신 예수님만 붙잡으라는 말씀이에요.$H$,
  memory_tip   = $H$세 덩어리로 끊어 외워 보세요. ①'너희가 십자가에 못 박히신 나사렛 예수를 찾는구나' ②'그가 살아나셨고' ③'여기 계시지 아니하니라'. 여인들이 텅 빈 무덤을 들여다보는 장면을 떠올리면 뒷부분이 잘 이어져요.$H$
where id = '_IGCmd3z_tQ';   -- 막 16:6 빈 손, 빈 무덤
update public.sermons set
  easy_explain = $H$이 구절은 하나님을 사랑한다면 어떻게 살아야 하는지 세 가지로 알려 줘요. 명령을 지키고, 그의 길을 따라가고, 그를 경외하는 것이에요. 여기서 '그의 길을 따라간다'는 건 하나님이 걷게 하신 길을 신뢰하며 걷는다는 뜻이에요. 광야 40년처럼요. '경외하다'는 하나님을 무서워하는 게 아니라 크신 분으로 높이고 사랑하는 마음이에요. 이해돼서가 아니라 믿기 때문에 그 말씀대로 사는 것이랍니다.$H$,
  memory_tip   = $H$세 동작으로 끊어 외워 보세요. ①'명령을 지켜' ②'그의 길을 따라가며' ③'그를 경외할지라'. 모두 하나님을 향하는 행동이라 '지켜-따라가며-경외할지라' 세 낱말만 순서대로 떠올리면 쉬워요. 앞머리만 따면 '지·따·경'이랍니다.$H$
where id = 'WZLKQa_cSdI';   -- 신 8:6 기억하고 선포하고 순종하라
update public.sermons set
  easy_explain = $H$예수님이 마귀에게 하신 대답이에요. 마귀는 절 한 번만 하면 온 세상 권력과 영광을 주겠다고 했지만, 예수님은 하나님 한 분만 높이고 섬기겠다고 하셨어요. 여기서 '경배'는 무릎 꿇고 높인다는 뜻이고, '다만'은 '오직 그분만'이라는 뜻이에요. 세상의 좋은 것보다 하나님 한 분으로 기뻐하는 것이 가장 큰 복이라는 말씀이에요.$H$,
  memory_tip   = $H$두 덩어리로 끊어 외워 보세요. 앞은 '주 너의 하나님께 경배하고', 뒤는 '다만 그를 섬기라'예요. '경배하고—섬기라' 두 동작이 짝을 이루고, 사이에 '다만(오직)'이 딱 들어간다고 그림 그리듯 떠올리면 쉬워요.$H$
where id = 'vRQzw_vTYxw';   -- 눅 4:8 광야의 세 가지 질문
update public.sermons set
  easy_explain = $H$루디아라는 여인이 바울의 말을 듣고 그대로 따랐어요. 그런데 그렇게 되도록 그녀의 마음을 연 분은 바울도, 주변 사람도 아닌 바로 '주님'이셨어요. 여기서 '마음을 열어'는 꽉 닫혀 있던 마음문이 활짝 열려 하나님 말씀을 받아들이게 됐다는 뜻이에요. 사람의 마음문은 안에서만 잠기기에, 그것을 여시는 분은 오직 주님뿐이랍니다.$H$,
  memory_tip   = $H$짧은 구절이니 '주께서 그 마음을 열어' / '바울의 말을 따르게 하신지라' 두 덩어리로 끊어 외워 보세요. '마음을 열어'서 '말을 따르게' 되는 순서가 자연스럽게 이어집니다. 문을 여시는 주님과 그 말을 따르는 루디아의 장면을 그려 보면 쉬워요.$H$
where id = '8fn81TLFXG8';   -- 행 16:14 마음을 여시는 하나님
update public.sermons set
  easy_explain = $H$하나님께서 "너는 내 것이야"라고 말씀하시는 구절이에요. 여기서 '소유'는 하나님이 우리를 자기 사람으로 아끼고 끝까지 책임져 주신다는 뜻이에요. '구별하였다'는 말은 많은 사람들 가운데서 나를 특별히 골라 세우셨다는 뜻이고요. 그러니 거룩하게 사는 건 억지로 잘 보이려는 게 아니라, 내가 하나님의 소유임을 기억할 때 자연스럽게 나오는 삶이에요.$H$,
  memory_tip   = $H$'내가 또 너희를 / 나의 소유로 삼으려고 / 너희를 만민 중에서 / 구별하였음이니라' 이렇게 네 덩어리로 끊어 외워 보세요. '너희를'이 두 번 반복되는 점을 붙잡으면 순서가 헷갈리지 않아요. 하나님이 사람들 무리 중에서 나를 콕 집어 데려오시는 장면을 그려 보면 쉽게 떠올라요.$H$
where id = '4vQWVvj7970';   -- 레 20:26 거룩하게 삽시다
update public.sermons set
  easy_explain = $H$이스라엘 백성이 광야를 걸어갈 때, 하나님은 낮에는 구름기둥으로 뜨거운 햇빛을 가려 주시고, 밤에는 불기둥으로 추위를 녹여 주셨어요. 여기서 '떠나지 아니하니라'는 하나님이 백성 앞을 한 번도 비우지 않으셨다는 뜻이에요. 우리는 하나님을 떠날 때가 있어도, 하나님은 우리를 절대 떠나지 않으시고 늘 앞서서 함께 걸어 주신다는 약속이랍니다.$H$,
  memory_tip   = $H$'낮에는 구름기둥 / 밤에는 불기둥 / 백성 앞에서 떠나지 아니하니라' 세 덩어리로 끊어 외워 보세요. '낮-구름, 밤-불'이 서로 짝을 이루는 대구라 그림을 그리면 쉬워요. 뜨거운 낮엔 구름, 추운 밤엔 불을 떠올리면 순서가 헷갈리지 않아요.$H$
where id = 'ZLE3C8GZvQI';   -- 출 13:22 믿고 가는 길
update public.sermons set
  easy_explain = $H$하나님께서 여호수아에게 하신 이 말씀은, 하나님의 말씀을 늘 입으로 소리 내어 되뇌며 그대로 살라는 뜻이에요. 여기서 '율법책'은 하나님이 주신 말씀을, '형통'은 하나님이 함께하셔서 잘되게 하신다는 뜻이에요. 큰 도전 앞에서 두려워하던 여호수아처럼, 우리도 말씀을 붙들고 순종하며 한 걸음 내디딜 때 하나님이 함께하시고 이끌어 주신다는 약속이랍니다.$H$,
  memory_tip   = $H$구절을 세 덩어리로 끊어 외워 보세요. ① '이 율법책을 네 입에서 떠나지 말게 하며' ② '다 지켜 행하라' ③ '그리하면 네가 형통하리라'. '입 → 행함 → 형통'으로 이어지는 순서를 그림처럼 떠올리면 쉽게 기억돼요.$H$
where id = 'qUewsTFzdzg';   -- 수 1:8 이 율법책을 네 입에서 떠나지 말게 하라
update public.sermons set
  easy_explain = $H$하나님이 아브라함에게 하신 약속이에요. "내가 네 이름을 창대하게 하리니"는 '내가 너를 크고 귀한 사람으로 만들어 주겠다'는 뜻이에요. 여기서 '창대하게'는 '아주 크고 빛나게 해 준다'는 말이에요. 그리고 "너는 복이 될지라"는 복을 받기만 하는 게 아니라, 나로 인해 다른 사람도 복을 받는 사람이 되라는 뜻이에요. 새해에 우리도 이런 복의 통로가 되라는 부르심이에요.$H$,
  memory_tip   = $H$두 덩어리로 끊어 외워 보세요. 앞은 하나님이 하시는 일 "내가 네 이름을 창대하게 하리니", 뒤는 나에게 주시는 부름 "너는 복이 될지라"예요. 앞부분 주어는 '내가(하나님)', 뒷부분 주어는 '너는(나)'으로 대비되니 이 주어를 짚으며 반복하면 순서가 헷갈리지 않아요.$H$
where id = 'clBpqFk4mMk';   -- 창 12:2 새해 복이 되세요
update public.sermons set
  easy_explain = $H$하나님의 말씀이 내가 걸어갈 때 발밑을 비춰 주는 등불 같다는 고백이에요. 여기서 '등'은 손바닥에 올려놓는 작은 등으로, 발 앞 한 걸음만 비춰 넘어지지 않게 해 줘요. 말씀은 먼 미래를 점치는 도구가 아니라 지금 이 순간 어디로 갈지 알려 주는 빛이에요. 그 한 걸음 한 걸음이 모여 주님이 이끄시는 복된 길에 이르게 됩니다.$H$,
  memory_tip   = $H$세 덩어리로 끊어 외워 보세요. '주의 말씀은 / 내 발에 등이요 / 내 길에 빛이니이다'. '등'과 '빛', '발'과 '길'이 짝을 이루니 이 대구를 떠올리면 쉬워요. 어두운 밤 작은 등을 들고 한 걸음씩 걷는 장면을 그려 보세요.$H$
where id = 'fEKH6MCOhtU';   -- 시 119:105 오직 성경, 말씀이 답이다! l 차동혁위임목사
update public.sermons set
  easy_explain = $H$이 말씀은 우리가 억지로 지켜야 할 규칙이 아니라, 성령님과 함께 살면 자연스럽게 나오는 '말투'예요. 성령님이 내 마음을 이끄시면 힘든 날에도 기뻐하고, 어려울 때 하나님께 기도하며, 모든 일에 감사하게 됩니다. 여기서 '범사'는 '모든 일'이라는 뜻이에요. 처음엔 외국어처럼 어색해도, 매일 성령님과 지내며 배우면 점점 내 모국어처럼 편해진답니다.$H$,
  memory_tip   = $H$세 문장이 똑같이 '~하라'로 끝나는 짧은 대구예요. '항상 기뻐하라 / 쉬지 말고 기도하라 / 범사에 감사하라'로 세 덩어리로 끊어 읽어 보세요. 첫 글자만 따면 '기·기·감(기뻐·기도·감사)'이라 기억하기 쉽답니다.$H$
where id = 'qdH4O1ocFes';   -- 살전 5:16-18 성령의 언어
update public.sermons set
  easy_explain = $H$다윗은 수많은 적들에게 둘러싸인 절박한 순간에도 무서워하지 않겠다고 말합니다. 여기서 '천만인'은 셀 수 없이 많은 사람, 즉 나를 죽이려는 온 무리를 뜻해요. '에워싸 진 친다'는 사방으로 완전히 포위당했다는 말이에요. 이렇게 도망갈 곳 없는 순간에도 다윗이 두렵지 않은 것은, 그 자리가 바로 하나님을 붙들고 기도하는 자리였기 때문이에요.$H$,
  memory_tip   = $H$구절을 세 덩어리로 끊어 보세요. '천만인이 나를 에워싸 진 친다 하여도' / '나는' / '두려워하지 아니하리이다'. 앞부분은 사방이 적으로 포위된 무서운 장면을 그려 보고, 뒷부분은 그럼에도 '나는 두렵지 않다'는 반전으로 기억하면 쉽게 외워집니다.$H$
where id = 'c686fX60fHg';   -- 시 3:6 천만인이 에워싸도 기도
update public.sermons set
  easy_explain = $H$이 구절은 아버지 다윗이 아들 솔로몬을 위해 드린 축복 기도예요. 하나님이 솔로몬에게 지혜와 총명을 주셔서, 그 지혜로 무엇보다 하나님의 말씀을 잘 지키며 살기를 바란다는 뜻이에요. 여기서 '지혜와 총명'은 똑똑해지는 것만이 아니라, 하나님 말씀대로 바르게 살아갈 힘을 말해요. 설교처럼, 믿음의 어른이 다음 세대를 위해 빌어 주는 사랑의 기도랍니다.$H$,
  memory_tip   = $H$세 덩어리로 끊어 외워요. '여호와께서 네게 지혜와 총명을 주사' / '네 하나님 여호와의 율법을 지키게 하시기를' / '더욱 원하노라'. 앞뒤에 '여호와'가 두 번 나오는 것과, 마지막이 '더욱 원하노라'로 힘주어 끝나는 점을 기억하세요.$H$
where id = 'ekyFC04potg';   -- 대상 22:12 다윗처럼 축복합니다
update public.sermons set
  easy_explain = $H$이 구절에서 '지혜'는 예수님을 가리켜요. 예수님을 사랑하고 곁에 두면, 그분이 나를 지켜 주신다는 약속이에요. 여기서 '버리지 말라'는 예수님을 무관심 속에 내버려 두지 말라는 뜻이고, '사랑하라'는 그분께 마음을 두고 가까이하라는 뜻이에요. 그분을 사랑하는 것이 가장 큰 지혜이고, 그러면 그분이 나를 보호하고 지켜 주세요.$H$,
  memory_tip   = $H$이 구절은 짝을 이루는 두 문장으로 되어 있어요. '지혜를 버리지 말라—그가 너를 보호하리라', '그를 사랑하라—그가 너를 지키리라'로 끊어 읽어 보세요. '버리지 말라·사랑하라'는 내가 할 일, '보호·지키리라'는 그분이 하실 일로 나눠 외우면 쉬워요.$H$
where id = 'zw6P2oNxrSE';   -- 잠 4:6 예수님을 대하는 법
update public.sermons set
  easy_explain = $H$이 구절은 다른 사람들과 달리 하나님을 끝까지 믿고 따른 갈렙에게 하나님이 복을 주시겠다는 약속이에요. 여기서 '온전히 따랐다'는 딴 마음 없이, 틈 없이 하나님만 가득 채워 따랐다는 뜻이에요. 사람들은 좋은 것을 보고도 '그래도'라며 하나님을 가볍게 여겼지만, 갈렙은 마음을 다르게 먹고 주님만 바라봤어요. 그래서 하나님은 그와 그 자손에게 좋은 땅을 주겠다고 하신 거예요.$H$,
  memory_tip   = $H$세 덩어리로 끊어 외워 보세요. ①'그러나 내 종 갈렙은' ②'그 마음이 그들과 달라서 나를 온전히 따랐은즉' ③'그의 자손이 그 땅을 차지하리라'. '마음이 달라서 → 온전히 따라서 → 땅을 차지'로 원인과 결과가 이어지는 흐름을 그림처럼 떠올리면 쉽게 기억됩니다.$H$
where id = 'njrok9CiqBE';   -- 민 14:24 갈렙처럼 보고 먹고 따르라
update public.sermons set
  easy_explain = $H$예수님을 믿는다는 이유로 힘든 일이나 놀림을 당할 때가 있어요. 그럴 때 부끄러워하지 말고 오히려 하나님께 감사하라는 말씀이에요. 여기서 '그리스도인'은 '예수님을 닮은 사람'이라는 뜻인데, 처음엔 놀리려고 부른 이름이었지만 우리에겐 최고의 칭찬이에요. 예수님 때문에 겪는 고난은 창피한 게 아니라, 오히려 하나님께 영광을 돌릴 기회랍니다.$H$,
  memory_tip   = $H$어색$H$
where id = 'YFtktRjB_bw';   -- 벧전 4:16 그리스도인이란
update public.sermons set
  easy_explain = $H$기드온이 전쟁에서 이긴 뒤 사람들이 '우리를 다스려 왕이 되어 주세요'라고 했을 때 한 대답이에요. 기드온은 '나는 왕이 안 될 거예요. 오직 하나님이 우리의 왕이세요'라고 고백한 거예요. 여기서 '다스리다'는 왕이 되어 사람들을 이끈다는 뜻이에요. 사람이 높은 자리에 올라도 진짜 왕은 나가 아니라 하나님이심을 기억하라는 말씀이에요.$H$,
  memory_tip   = $H$이 구절은 '내가'와 '여호와께서'가 짝을 이루는 대구예요. 앞은 '내가 너희를 다스리지 아니하겠고', 뒤는 '여호와께서 너희를 다스리시리라'로, 다스리는 주인공만 '나'에서 '여호와'로 바뀌지요. 두 문장을 나란히 놓고 소리 내어 읽으면 쉽게 외워져요.$H$
where id = 'mMnK13pKrWU';   -- 삿 8:23 1도의 위험
update public.sermons set
  easy_explain = $H$사람들이 예수님을 곤란하게 하려고 "세금을 내야 하나요?"라고 물었어요. 예수님은 동전에 황제의 얼굴이 새겨졌으니 황제 것은 황제에게 주라고 하셨어요. 여기서 '가이사'는 그 시대의 황제, 곧 세상 나라를 뜻해요. 하지만 우리 마음에는 하나님의 얼굴(형상)이 새겨져 있으니, 우리 자신은 하나님께 드리라는 뜻이에요.$H$,
  memory_tip   = $H$placeholder$H$
where id = 'enbDbanMMmc';   -- 막 12:17 아름다운 엉망진창
update public.sermons set
  easy_explain = $H$예수님이 제자들에게 주신 마지막 부탁이에요. '가서' 여러 나라 사람들을 예수님을 따르는 제자로 만들라고 하셨어요. 여기서 '제자로 삼다'는 그저 믿게만 하는 게 아니라, 함께 살아가는 가족으로 만드는 일이에요. 그리고 '아버지와 아들과 성령의 이름 안으로' 세례를 주라 하셨는데, 이는 사랑으로 하나이신 하나님의 집으로 이사 들어가 그 사랑 안에서 사는 것을 뜻해요.$H$,
  memory_tip   = $H$네 덩어리로 끊어 보세요. ①'너희는 가서' ②'모든 민족을 제자로 삼아' ③'아버지와 아들과 성령의 이름으로' ④'세례를 베풀고'. 특히 ③은 '아버지→아들→성령' 순서로 세 분을 손꼽으며 외우면 헷갈리지 않아요.$H$
where id = '7AyjSnmnbOc';   -- 마 28:19 아버지와 아들과 성령의 이름 안으로
update public.sermons set
  easy_explain = $H$이 말씀은 하나님을 믿고 마음을 하나님께 기대는 사람에게 하나님이 깊은 평안을 주신다는 뜻이에요. 여기서 '심지가 견고한 자'는 마음이 원래 단단한 사람이 아니라, 하나님께 마음을 딱 기대어 놓은 사람을 말해요. 또 '평강'은 문제가 하나도 없는 상태가 아니라, 나를 지켜 주시는 주님이 함께 계신 상태예요. 주님을 믿고 의지하면 그분이 우리를 든든히 지켜 주십니다.$H$,
  memory_tip   = $H$세 덩어리로 끊어 외워 보세요. '주께서 심지가 견고한 자를 / 평강하고 평강하도록 지키시리니 / 이는 그가 주를 신뢰함이니이다.' 특히 '평강하고 평강하도록'처럼 같은 말이 두 번 반복되는 부분을 소리 내어 강조하면 잘 외워져요.$H$
where id = 'JMGk_9xJ7rc';   -- 사 26:3 샬롬 샬롬
update public.sermons set
  easy_explain = $H$감옥의 간수가 바울에게 "어떻게 해야 구원을 받나요?"라고 물었을 때 대답한 말이에요. 여기서 '믿으라'는 우리가 무언가를 잘해서 구원을 얻는 게 아니라, 십자가에서 죽고 다시 사신 주 예수님을 마음으로 받아들이라는 뜻이에요. '너와 네 집'은 나 한 사람만이 아니라 우리 가족까지라는 말이에요. 한 사람의 참된 믿음이 온 가정에 큰 기쁨과 구원으로 흘러간다는 약속이랍니다.$H$,
  memory_tip   = $H$두 덩어리로 끊어 보세요. 앞부분은 명령 "주 예수를 믿으라", 뒷부분은 그 결과 "그리하면 너와 네 집이 구원을 받으리라"예요. '믿으라 → 그리하면'으로 원인과 결과가 이어지는 구조를 떠올리면 순서가 쉽게 기억돼요.$H$
where id = 'O6NmpvcYyD8';   -- 행 16:31 O6NmpvcYyD8
update public.sermons set
  easy_explain = $H$예수님이 예루살렘에 들어가시기 전, 제자들에게 어린 나귀를 데려오라고 하십니다. 누가 왜 나귀를 푸느냐고 묻거든 '주가 쓰시겠다'고만 말하라고 하신 거예요. 여기서 '주'는 예수님을 뜻하고, '쓰시겠다'는 주님이 나를 필요로 하신다는 말이에요. 주님이 부르실 때 화려한 재능이 아니라, 볼품없고 매인 나귀 같은 나라도 즉시 내어드리면 귀하게 쓰임받는다는 뜻입니다.$H$,
  memory_tip   = $H$두 덩어리로 끊어 외워 보세요. 앞은 '주가 쓰시겠다 하라', 뒤는 '그리하면 즉시 이리로 보내리라'. '하라 → 그리하면'으로 말과 결과가 이어지는 구조예요. 나귀 주인이 곧바로 나귀를 풀어 보내는 장면을 그리며 '즉시'를 힘주어 외우면 잘 붙습니다.$H$
where id = 'jg50nRA68vc';   -- 막 11:3 jg50nRA68vc
update public.sermons set
  easy_explain = $H$이 구절은 '하나님이 내 기도를 들어주셨기 때문에 내가 하나님을 사랑한다'는 고백이에요. 여기서 '음성'은 내가 하나님께 소리 내어 부르는 것이고, '간구'는 도와달라고 간절히 비는 기도예요. 설교의 하갈처럼, 광야에서 홀로 울부짖을 때 하나님이 그 울음을 들어주시고 샘물로 응답하셨듯이, 하나님은 우리 기도를 꼭 들어주세요. 그 들어주심을 경험할수록 하나님을 더 사랑하게 된답니다.$H$,
  memory_tip   = $H$'들으시므로'를 중심으로 앞뒤 두 덩어리로 끊어 보세요. 앞은 '내 음성과 내 간구를 들으시므로'(하나님이 하신 일), 뒤는 '내가 그를 사랑하는도다'(그래서 내가 하는 일). '들으심 → 사랑함'의 순서를 그림처럼 떠올리면 쉽게 외워져요.$H$
where id = '-7OqMxRHOdM';   -- 시 116:1 -7OqMxRHOdM

select count(*) as 도우미_보유_편수 from public.sermons where easy_explain is not null;
